import {
  Lucid,
  Blockfrost,
  Data,
  fromText,
  Constr,
} from "https://unpkg.com/lucid-cardano@0.10.11/web/mod.js";

// ========= CONFIG =========
export const BLOCKFROST_URL = "https://cardano-preprod.blockfrost.io/api/v0";
export const BLOCKFROST_KEY = "preprodYjRkHfcazNkL0xxG9C2RdUbUoTrG7wip";
export const NETWORK = "Preprod";

export const AUTHORITY_ADDRESS =
  "addr_test1qqe5zn0qmu9hga5xlqp4ae4cxq4g0vmtyac0g2zv0mh5kfhsn2ld9h4unte6gjsml94j9rsk8kktpvf0dqznl629esdsk76wfv";

// Paste compiled CBORs here
export const LAND_POLICY_CBOR = "";
export const LAND_VALIDATOR_CBOR = "";

// ========= STATE =========
let lucid;
let AUTHORITY_PKH_HEX;

// ========= DATA SCHEMA =========
export const LandDatum = Data.Object({
  ldParcelId: Data.Bytes(), // hex bytes
  ldOwnerPkh: Data.Bytes(), // 56-hex PKH
});

// ========= REDEEMERS (Constr-based: avoids Data.Enum crash) =========
// Constr 0 = Transfer(newOwnerPkh)
export function mkTransferRedeemer(newOwnerPkhHex) {
  return Data.to(new Constr(0, [newOwnerPkhHex]));
}

// Constr 0 = Mint(parcelBytes)
export function mkMintRedeemer(parcelBytesHex) {
  return Data.to(new Constr(0, [parcelBytesHex]));
}

// Constr 1 = Burn(parcelBytes)
export function mkBurnRedeemer(parcelBytesHex) {
  return Data.to(new Constr(1, [parcelBytesHex]));
}

// ========= HELPERS =========
function assertPkhHex(pkh) {
  const v = (pkh || "").toLowerCase().trim();
  if (!/^[0-9a-f]{56}$/.test(v)) throw new Error("PKH must be 56 hex chars (no 0x).");
  return v;
}

async function sha256HexFromText(txt) {
  const bytes = new TextEncoder().encode(txt);
  const hash = await crypto.subtle.digest("SHA-256", bytes);
  return [...new Uint8Array(hash)].map(b => b.toString(16).padStart(2, "0")).join("");
}

export async function tokenNameHexFromParcelId(parcelIdStr) {
  return await sha256HexFromText(parcelIdStr);
}

export function getLucid() {
  if (!lucid) throw new Error("Lucid not initialized. Call connectWallet first.");
  return lucid;
}

export function getLandScript() {
  return { type: "PlutusV2", script: LAND_VALIDATOR_CBOR };
}

export function getLandScriptAddress() {
  return lucid.utils.validatorToAddress(getLandScript());
}

export function authorityPkhFromAddress(authorityAddr) {
  const details = lucid.utils.getAddressDetails(authorityAddr);
  if (!details.paymentCredential || details.paymentCredential.type !== "Key")
    throw new Error("Authority address must be a key payment address");
  return details.paymentCredential.hash;
}

export async function myPkh() {
  const addr = await lucid.wallet.address();
  const details = lucid.utils.getAddressDetails(addr);
  if (!details.paymentCredential || details.paymentCredential.type !== "Key")
    throw new Error("Wallet must be a key payment address");
  return details.paymentCredential.hash;
}

// ========= SETUP =========
export async function connectWallet(walletName = "lace") {
  lucid = await Lucid.new(new Blockfrost(BLOCKFROST_URL, BLOCKFROST_KEY), NETWORK);

  const api = await window.cardano[walletName].enable();
  lucid.selectWallet(api);

  AUTHORITY_PKH_HEX = authorityPkhFromAddress(AUTHORITY_ADDRESS);

  return {
    address: await lucid.wallet.address(),
    myPkh: await myPkh(),
    authorityPkh: AUTHORITY_PKH_HEX,
    landScriptAddress: getLandScriptAddress(),
  };
}

export async function computePolicyId() {
  const policy = { type: "PlutusV2", script: LAND_POLICY_CBOR };
  return lucid.utils.mintingPolicyToId(policy);
}

// ========= 1) REGISTER LAND (Authority wallet page) =========
export async function registerLandOnchain({ parcelId, initialOwnerPkhHex }) {
  if (!AUTHORITY_PKH_HEX) throw new Error("Connect wallet first");

  const policy = { type: "PlutusV2", script: LAND_POLICY_CBOR };
  const policyId = lucid.utils.mintingPolicyToId(policy);

  const tnHex = await tokenNameHexFromParcelId(parcelId);
  const unit = policyId + tnHex;

  const landAddr = getLandScriptAddress();
  const parcelBytesHex = fromText(parcelId);

  const datum = Data.to(
    { ldParcelId: parcelBytesHex, ldOwnerPkh: assertPkhHex(initialOwnerPkhHex) },
    LandDatum
  );

  const mintRedeemer = mkMintRedeemer(parcelBytesHex);

  const tx = await lucid
    .newTx()
    .mintAssets({ [unit]: 1n }, mintRedeemer)
    .payToContract(landAddr, { inline: datum }, { [unit]: 1n, lovelace: 2_000_000n })
    .attachMintingPolicy(policy)
    .addSignerKey(AUTHORITY_PKH_HEX)
    .complete();

  const signed = await tx.sign().complete();
  const txHash = await signed.submit();

  return { txHash, policyId, tokenNameHex: tnHex, unit, landAddr };
}

// ========= 2) OWNER REQUEST TRANSFER (Owner page) =========
export async function ownerRequestTransferOnchain({ parcelId, newOwnerPkhHex, policyId }) {
  const tnHex = await tokenNameHexFromParcelId(parcelId);
  const unit = policyId + tnHex;

  const landAddr = getLandScriptAddress();
  const parcelBytesHex = fromText(parcelId);

  const utxos = await lucid.utxosAt(landAddr);
  const target = utxos.find(u => {
    if (!u.datum) return false;
    const d = Data.from(u.datum, LandDatum);
    return d.ldParcelId === parcelBytesHex;
  });
  if (!target) throw new Error("Land UTxO not found for parcelId");

  const newDatum = Data.to(
    { ldParcelId: parcelBytesHex, ldOwnerPkh: assertPkhHex(newOwnerPkhHex) },
    LandDatum
  );

  const redeemer = mkTransferRedeemer(assertPkhHex(newOwnerPkhHex));

  const tx = await lucid
    .newTx()
    .collectFrom([target], redeemer)
    .payToContract(landAddr, { inline: newDatum }, { [unit]: 1n, lovelace: 2_000_000n })
    .attachSpendingValidator(getLandScript())
    .addSignerKey(await myPkh())
    .addSignerKey(AUTHORITY_PKH_HEX)
    .complete();

  const ownerSigned = await tx.sign().complete();
  return { partialTxCbor: ownerSigned.toString() };
}

// ========= 3) AUTHORITY COSIGN + SUBMIT (Authority page) =========
export async function authorityCosignAndSubmit({ partialTxCbor }) {
  const tx = lucid.fromTx(partialTxCbor);
  const signed = await tx.sign().complete();
  const txHash = await signed.submit();
  return { txHash };
}

// ========= PUBLIC VERIFY HELPERS =========
export async function getOnchainOwnerForParcel({ parcelId }) {
  const landAddr = getLandScriptAddress();
  const parcelBytesHex = fromText(parcelId);

  const utxos = await lucid.utxosAt(landAddr);
  const target = utxos.find(u => {
    if (!u.datum) return false;
    const d = Data.from(u.datum, LandDatum);
    return d.ldParcelId === parcelBytesHex;
  });
  if (!target) return null;

  const d = Data.from(target.datum, LandDatum);
  return { ownerPkh: d.ldOwnerPkh, utxo: target };
}